 184→/// Capitalize the first character of a string (for Go exported names).
 185→fn capitalize_first(s: &str) -> String {
 186→    let mut chars = s.chars();
 187→    match chars.next() {
 188→        None => String::new(),
 189→        Some(c) => c.to_uppercase().collect::<String>() + chars.as_str(),
 190→    }
 191→}
 192→
 193→/// Map a JSON value to a Go type string.
 194→fn go_type_from_value(value: &serde_json::Value) -> String {
 195→    // Check for __complex_type tagged objects first
 196→    if let Some(obj) = value.as_object()
 197→        && let Some(tag) = obj.get("__complex_type").and_then(|t| t.as_str())
 198→    {
 199→        return go_type_from_complex(tag);
 200→    }
 201→    match value {
 202→        serde_json::Value::String(_) => "string".to_string(),
 203→        serde_json::Value::Bool(_) => "bool".to_string(),
 204→        serde_json::Value::Number(n) => {
 205→            if n.is_f64() && n.to_string().contains('.') {
 206→                "float64".to_string()
 207→            } else {
 208→                "int".to_string()
 209→            }
 210→        }
 211→        serde_json::Value::Null => "interface{}".to_string(),
 212→        serde_json::Value::Array(_) => "interface{}".to_string(),
 213→        serde_json::Value::Object(_) => "interface{}".to_string(),
 214→    }
 215→}
 216→
 217→/// Map a complex type tag to its Go type name.
 218→fn go_type_from_complex(tag: &str) -> String {
 219→    match tag {
 220→        "date" | "date_time" => "time.Time".to_string(),
 221→        "duration" => "time.Duration".to_string(),
 222→        "reg_exp" => "*regexp.Regexp".to_string(),
 223→        "big_int" => "*big.Int".to_string(),
 224→        "big_decimal" => "*big.Float".to_string(),
 225→        "url" => "*url.URL".to_string(),
 226→        "ip_address" => "net.IP".to_string(),
 227→        "error" => "error".to_string(),
 228→        "rune" => "rune".to_string(),
 229→        "go_byte" => "byte".to_string(),
 230→        _ => "interface{}".to_string(),
 231→    }
 232→}
 233→
 234→/// Format a JSON value as a Go literal.
 235→///
 236→/// Detects `__complex_type` tagged objects and emits constructor calls.
 237→fn format_go_value(value: &serde_json::Value) -> String {
 238→    if let Some(go) = try_format_complex_go(value) {
 239→        return go;
 240→    }
 241→    match value {
 242→        serde_json::Value::String(s) => format!("\"{}\"", s.replace('\\', "\\\\").replace('"', "\\\"")),
 243→        serde_json::Value::Null => "nil".to_string(),
 244→        serde_json::Value::Bool(b) => b.to_string(),
 245→        serde_json::Value::Number(n) => n.to_string(),
 246→        other => format!("/* unsupported: {} */nil", other),
 247→    }
 248→}
 249→
 250→/// Try to format a `__complex_type` tagged JSON object as a Go constructor.
 251→/// Returns `None` if the value is not a tagged complex type.
 252→fn try_format_complex_go(value: &serde_json::Value) -> Option<String> {
 253→    let obj = value.as_object()?;
 254→    let tag = obj.get("__complex_type")?.as_str()?;
 255→    match tag {
 256→        "date" | "date_time" => {
 257→            let v = obj.get("value")?;
 258→            Some(format!("time.UnixMilli({})", v))
 259→        }
 260→        "duration" => {
 261→            let ms = obj.get("ms").or_else(|| obj.get("value"))?;
 262→            Some(format!("time.Duration({}) * time.Millisecond", ms))
 263→        }
 264→        "reg_exp" => {
 265→            let source = obj.get("source")?.as_str()?;
 266→            let escaped = source.replace('\\', "\\\\").replace('"', "\\\"");
 267→            Some(format!("regexp.MustCompile(\"{escaped}\")"))
 268→        }
 269→        "big_int" => {
 270→            let v = obj.get("value")?.as_str()?;
 271→            Some(format!("func() *big.Int {{ n, _ := new(big.Int).SetString(\"{v}\", 10); return n }}()"))
 272→        }
 273→        "url" => {
 274→            let v = obj.get("value")?.as_str()?;
 275→            let escaped = v.replace('"', "\\\"");
 276→            Some(format!("func() *url.URL {{ u, _ := url.Parse(\"{escaped}\"); return u }}()"))
 277→        }
 278→        "error" => {
 279→            let msg = obj.get("message").and_then(|m| m.as_str()).unwrap_or("");
 280→            let escaped = msg.replace('"', "\\\"");
 281→            Some(format!("errors.New(\"{escaped}\")"))
 282→        }
 283→        "uuid" => {
 284→            let v = obj.get("value")?.as_str()?;
 285→            Some(format!("/* uuid */ \"{v}\""))
 286→        }
 287→        "ip_address" => {
 288→            let v = obj.get("value")?.as_str()?;
 289→            Some(format!("net.ParseIP(\"{v}\")"))
 290→        }
 291→        "rune" => {
 292→            let v = obj.get("value")?.as_str()?;
 293→            if let Some(ch) = v.chars().next() {
 294→                Some(format!("'{ch}'"))
 295→            } else {
 296→                Some("0".to_string())
 297→            }
 298→        }
 299→        "go_byte" => {
 300→            let v = obj.get("value")?;
 301→            Some(format!("byte({})", v))
 302→        }
 303→        _ => None,
 304→    }
 305→}
 306→
 307→/// Return the Go zero value for a type name.
 308→fn go_zero_value(type_name: &str) -> String {
 309→    match type_name {
 310→        "string" => "\"\"".to_string(),
 311→        "int" => "0".to_string(),
 312→        "float64" => "0.0".to_string(),
 313→        "bool" => "false".to_string(),
 314→        _ => "nil".to_string(),
 315→    }
 316→}
