2944→
2945→    shutdown_frontend(frontend).await;
2946→
2947→    let existing = shatter_core::spec::read_file_spec_bundle(spec_path)
2948→        .map_err(|e| format!("failed to read spec file {}: {e}", spec_path.display()))?;
