2957→            "stale": plan.stale,
2958→            "fresh": plan.fresh,
2959→            "removed": plan.removed,
2960→            "all_fresh": all_fresh,
2961→        });
2962→        println!("{}", serde_json::to_string_pretty(&output)?);
2963→    } else {
2964→        if !plan.stale.is_empty() {
2965→            println!("Stale ({}):", plan.stale.len());
2966→            for name in &plan.stale {
2967→                println!("  {name}");
2968→            }
2969→        }
2970→        if !plan.fresh.is_empty() {
2971→            println!("Fresh ({}):", plan.fresh.len());
